167: // InstallHandler registers handlers for health checking on the path
168: // "/healthz" to mux. *All handlers* for mux must be specified in
169: // exactly one call to InstallHandler. Calling InstallHandler more
170: // than once for the same mux will result in a panic.
171: func InstallHandler(mux mux, checks ...HealthChecker) {
172: 	InstallPathHandler(mux, DefaultHealthzPath, checks...)
173: }
174: 
175: // InstallReadyzHandler registers handlers for health checking on the path
176: // "/readyz" to mux. *All handlers* for mux must be specified in
177: // exactly one call to InstallHandler. Calling InstallHandler more
178: // than once for the same mux will result in a panic.
179: func InstallReadyzHandler(mux mux, checks ...HealthChecker) {
180: 	InstallPathHandler(mux, "/readyz", checks...)
181: }
182: 
183: // InstallLivezHandler registers handlers for liveness checking on the path
184: // "/livez" to mux. *All handlers* for mux must be specified in
185: // exactly one call to InstallHandler. Calling InstallHandler more
186: // than once for the same mux will result in a panic.
187: func InstallLivezHandler(mux mux, checks ...HealthChecker) {
188: 	InstallPathHandler(mux, "/livez", checks...)
189: }
190: 
191: // InstallPathHandler registers handlers for health checking on
192: // a specific path to mux. *All handlers* for the path must be
193: // specified in exactly one call to InstallPathHandler. Calling
194: // InstallPathHandler more than once for the same path and mux will
195: // result in a panic.
196: func InstallPathHandler(mux mux, path string, checks ...HealthChecker) {
197: 	InstallPathHandlerWithHealthyFunc(mux, path, nil, checks...)
198: }
199: 
200: // InstallPathHandlerWithHealthyFunc is like InstallPathHandler, but calls firstTimeHealthy exactly once
201: // when the handler succeeds for the first time.
202: func InstallPathHandlerWithHealthyFunc(mux mux, path string, firstTimeHealthy func(), checks ...HealthChecker) {
203: 	if len(checks) == 0 {
204: 		klog.V(5).Info("No default health checks specified. Installing the ping handler.")
205: 		checks = []HealthChecker{PingHealthz}
206: 	}
207: 
208: 	klog.V(5).Infof("Installing health checkers for (%v): %v", path, formatQuoted(checkerNames(checks...)...))
209: 
210: 	name := strings.Split(strings.TrimPrefix(path, "/"), "/")[0]
211: 	mux.Handle(path,
212: 		metrics.InstrumentHandlerFunc("GET",
213: 			/* group = */ "",
214: 			/* version = */ "",
215: 			/* resource = */ "",
216: 			/* subresource = */ path,
217: 			/* scope = */ "",
218: 			/* component = */ "",
219: 			/* deprecated */ false,
220: 			/* removedRelease */ "",
221: 			handleRootHealth(name, firstTimeHealthy, checks...)))
222: 	for _, check := range checks {
223: 		mux.Handle(fmt.Sprintf("%s/%v", path, check.Name()), adaptCheckToHandler(check.Check))
224: 	}
225: }
226: 
227: // mux is an interface describing the methods InstallHandler requires.
228: type mux interface {
229: 	Handle(pattern string, handler http.Handler)
230: }
231: 
232: // healthzCheck implements HealthChecker on an arbitrary name and check function.
233: type healthzCheck struct {
234: 	name  string
235: 	check func(r *http.Request) error
236: }
237: 
238: var _ HealthChecker = &healthzCheck{}
239: 
240: func (c *healthzCheck) Name() string {
241: 	return c.name
242: }
243: 
244: func (c *healthzCheck) Check(r *http.Request) error {
245: 	return c.check(r)
246: }
247: 
248: type groupedHealthzCheck struct {
249: 	groupName string
250: 	HealthChecker
251: }
252: 
